import React from 'react'
import { RiDoubleQuotesL, RiDoubleQuotesR } from 'react-icons/ri'
import './program6b.css'
import { Page6bNienKhoaContent } from '../../contexts/CMSContext'

type Props = {
  data: Page6bNienKhoaContent
}

const Page6bNienKhoa: React.FC<Props> = ({ data }) => {
  return (
    <section className="page6b-nienkhoa-section">
      {data.blocks.map(block => {
        if (block.type === 'schedule') {
          return (
            <div key={block.id} className="page6b-nienkhoa-block">
              <div className="page6b-nienkhoa-content">
                <h2 className="page6b-nienkhoa-title">{block.title}</h2>
                <div className="page6b-nienkhoa-underline" />

                <h3 className="page6b-nienkhoa-course-title">
                  {block.schedules.heading}
                </h3>

                <div className="page6b-nienkhoa-schedule">
                  {block.schedules.items.map(item => (
                    <div key={item.id} className="page6b-schedule-item">
                      <strong>{item.dayLabel}</strong>
                      <div className="page6b-schedule-details">
                        {item.details.map((d, i) => (
                          <div key={i}>{d}</div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              <div className="page6b-nienkhoa-image">
                <img src={block.imageDesktop} alt={block.title} />
                {block.imageMobile && (
                  <div className="page6b-mobile-overlay">
                    <h2 className="page6b-nienkhoa-mobile-title">
                      {block.title}
                    </h2>
                  </div>
                )}
              </div>
            </div>
          )
        }

        if (block.type === 'course') {
          return (
            <div key={block.id} className="page6b-nienkhoa-block">
              <div className="page6b-nienkhoa-content">
                <h2 className="page6b-nienkhoa-title">{block.title}</h2>
                <div className="page6b-nienkhoa-underline" />

                {block.courses.map(course => (
                  <div key={course.id} className="page6b-nienkhoa-course">
                    <h3 className="page6b-nienkhoa-course-title2">
                      {course.title}
                    </h3>
                    <p className="page6b-nienkhoa-paragraph">
                      <RiDoubleQuotesL className="quote-left" />
                      {course.description}
                      <RiDoubleQuotesR className="quote-right" />
                    </p>
                  </div>
                ))}
              </div>

              <div className="page6b-nienkhoa-image">
                <img src={block.imageDesktop} alt={block.title} />
              </div>
            </div>
          )
        }

        return null
      })}
    </section>
  )
}

export default Page6bNienKhoa
